@classmethod
    def _get_file_path(cls, project_dir, module_name, file_id, file_name):
        """Get the full path of a project file for secure storage.

        Tandaan: Ginagamit ito para i-save ang mga dokumento ng proyekto sa
        tamang folder base sa module at ID. Siguraduhing hindi mabago ang
        istraktura ng folder para hindi magkaroon ng problema sa pag-access.
        """
        path = os.path.join(project_dir, 'secure_files', module_name, file_id)
        os.makedirs(path, exist_ok=True)
        return os.path.join(path, file_name)

