  validatePhotoUpload: function (event) {
    event.preventDefault();
    // Alisin ang mga nakaraang error messages.
    $('.photo-upload-js-error').remove();

    // Magdagdag ng client-side validation para sa input[type=file].
    var allowedTypes = ['image/jpeg', 'image/png', 'image/gif'];
    var maxSize = 5 * 1024 * 1024; // 5MB ang maximum size.
    var file = event.target.files[0];

    if (file) {
      if (!allowedTypes.includes(file.type)) {
        $('.photo-upload-js').after('<div class="photo-upload-js-error">Dapat JPEG, PNG, o GIF lang ang file.</div>');
      } else if (file.size > maxSize) {
        $('.photo-upload-js').after('<div class="photo-upload-js-error">Ang laki ng file ay hindi dapat lumampas sa 5MB.</div>');
      } else {
        $('.photo-upload-js').after('<div class="photo-upload-js-success">Valid na file! Maaari mo nang i-upload.</div>');
      }
    }
